459	    #[test]
460	    fn full_schema_parses() {
461	        let (_cfg, path) = write_cfg(
462	            "full",
463	            r#"[default]
464	account = "home"
465	debug   = "trace"
466	
467	[account.home]
468	repo.default          = "remote"
469	repo.category.remote  = "git@github.com:winksaville"
470	repo.category.local   = "~/test-fixtures"
471	
472	[account.work]
473	repo.default          = "remote"
474	repo.category.remote  = "git@github.com:anthropic"
475	repo.category.local   = "/work/fixtures"
476	"#,
477	        );
478	        let cfg = load_from(&path).unwrap();
479	        assert_eq!(cfg.default_account.as_deref(), Some("home"));
480	        assert_eq!(cfg.default_debug.as_deref(), Some("trace"));
481	        assert_eq!(cfg.accounts.len(), 2);
482	
483	        let home = cfg.accounts.get("home").expect("home account");
484	        assert_eq!(home.repo_default.as_deref(), Some("remote"));
485	        assert_eq!(
486	            home.repo_category.get("remote").map(String::as_str),
487	            Some("git@github.com:winksaville")
488	        );
489	        assert_eq!(
490	            home.repo_category.get("local").map(String::as_str),
491	            Some("~/test-fixtures")
492	        );
493	
494	        let work = cfg.accounts.get("work").expect("work account");
495	        assert_eq!(work.repo_default.as_deref(), Some("remote"));
496	        assert_eq!(
497	            work.repo_category.get("remote").map(String::as_str),
498	            Some("git@github.com:anthropic")
499	        );
500	    }
