560	    #[test]
561	    fn unknown_keys_ignored() {
562	        // Forward-compat: unknown sections/sub-keys silently dropped.
563	        let (_cfg, path) = write_cfg(
564	            "unknown",
565	            r#"[account.home]
566	repo.category.remote = "git@github.com:wink"
