578	    // ---------- resolve_repo ----------
579	
580	    fn cfg_with_two_accounts() -> UserConfig {
581	        let home = AccountConfig {
582	            repo_default: Some("remote".into()),
583	            repo_category: HashMap::from([
584	                ("remote".into(), "git@github.com:winksaville".into()),
585	                ("local".into(), "~/test-fixtures".into()),
586	            ]),
587	        };
588	        let work = AccountConfig {
589	            repo_default: Some("remote".into()),
590	            repo_category: HashMap::from([
591	                ("remote".into(), "git@github.com:anthropic".into()),
592	                ("local".into(), "/work/fixtures".into()),
593	            ]),
594	        };
595	        UserConfig {
